import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.DdLJaIXX.js";const k=JSON.parse('{"title":"Knowledge Loop","description":"","frontmatter":{},"headers":[],"relativePath":"ko/guide/growth-loop.md","filePath":"ko/guide/growth-loop.md"}'),n={name:"ko/guide/growth-loop.md"};function l(p,s,h,o,d,r){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="knowledge-loop" tabindex="-1">Knowledge Loop <a class="header-anchor" href="#knowledge-loop" aria-label="Permalink to &quot;Knowledge Loop&quot;">​</a></h1><p>CQ는 당신의 작업 방식과 GPU 실험 결과를 학습하여 AI 동작을 선호도에 맞게 영구적으로 변경합니다.</p><h2 id="해결하는-문제" tabindex="-1">해결하는 문제 <a class="header-anchor" href="#해결하는-문제" aria-label="Permalink to &quot;해결하는 문제&quot;">​</a></h2><p>AI 세션은 매번 처음부터 시작됩니다. 당신의 규칙을 설명하고, 같은 실수를 수정하고, 같은 제약사항을 다시 말합니다 — 세션마다. Knowledge Loop는 이 루프를 닫습니다.</p><h2 id="동작-방식" tabindex="-1">동작 방식 <a class="header-anchor" href="#동작-방식" aria-label="Permalink to &quot;동작 방식&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>세션 종료 → 선호도 추출 → 카운트 증가</span></span>
<span class="line"><span>                                │</span></span>
<span class="line"><span>                      count ≥ 3 → CLAUDE.md에 힌트 기록</span></span>
<span class="line"><span>                      count ≥ 5 → .claude/rules/에 규칙으로 승격</span></span>
<span class="line"><span>                                   AI 동작이 영구적으로 변화</span></span></code></pre></div><p>네 가지 컴포넌트:</p><table tabindex="0"><thead><tr><th>컴포넌트</th><th>역할</th></tr></thead><tbody><tr><td><strong>PreferenceLedger</strong></td><td>관찰된 선호도를 발생 횟수와 함께 저장</td></tr><tr><td><strong>Hints</strong></td><td><code>CLAUDE.md</code>에 추가되는 제안 (count ≥ 3)</td></tr><tr><td><strong>Rules</strong></td><td><code>.claude/rules/</code>의 영구 동작 규칙 (count ≥ 5)</td></tr><tr><td><strong>GlobalPromoter</strong></td><td>패턴을 비개인화하여 커뮤니티 풀에 공유</td></tr></tbody></table><h2 id="실제-사례" tabindex="-1">실제 사례 <a class="header-anchor" href="#실제-사례" aria-label="Permalink to &quot;실제 사례&quot;">​</a></h2><p>5번의 ML 연구 세션 후, CQ가 관찰된 동작에서 자동으로 학습한 패턴:</p><table tabindex="0"><thead><tr><th>발생 횟수</th><th>레벨</th><th>CQ가 학습한 것</th></tr></thead><tbody><tr><td>5x</td><td><strong>Rule</strong></td><td>&quot;Hub를 통해 자동으로 실험 실행&quot;</td></tr><tr><td>4x</td><td>Hint</td><td>&quot;<code>@key=value</code> 메트릭 출력 형식 사용&quot;</td></tr><tr><td>4x</td><td>Hint</td><td>&quot;MPJPE/HD/MSD 메트릭 먼저 확인&quot;</td></tr><tr><td>3x</td><td>Hint</td><td>&quot;시작 전 항상 <code>cq doctor</code> 실행&quot;</td></tr></tbody></table><p>이 규칙들은 <code>CLAUDE.md</code>와 <code>.claude/rules/</code>에 주입되어 — 이후 모든 세션의 시스템 프롬프트에 로드됩니다.</p><h2 id="선호도-→-hint-→-rule-생명주기" tabindex="-1">선호도 → Hint → Rule 생명주기 <a class="header-anchor" href="#선호도-→-hint-→-rule-생명주기" aria-label="Permalink to &quot;선호도 → Hint → Rule 생명주기&quot;">​</a></h2><h3 id="_1단계-관찰" tabindex="-1">1단계: 관찰 <a class="header-anchor" href="#_1단계-관찰" aria-label="Permalink to &quot;1단계: 관찰&quot;">​</a></h3><p>세션이 종료될 때 선호도가 추출됩니다. 출처:</p><ul><li>AI 출력에 대한 수정 사항</li><li>코드 리뷰 또는 실험 결과 검토 방식의 패턴</li><li>반복적으로 실행한 커맨드</li><li>세션 중 명시적으로 제시한 지침</li></ul><h3 id="_2단계-hint-count-≥-3" tabindex="-1">2단계: Hint (count ≥ 3) <a class="header-anchor" href="#_2단계-hint-count-≥-3" aria-label="Permalink to &quot;2단계: Hint (count ≥ 3)&quot;">​</a></h3><p>CQ가 <code>CLAUDE.md</code>에 제안을 추가합니다:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- CQ hint: count=3 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">포즈 추정 결과 평가 시 MPJPE/HD/MSD 메트릭을 먼저 확인하세요.</span></span></code></pre></div><p>Hint는 소프트 가이던스입니다 — AI가 참고하지만 동작을 강제하지는 않습니다.</p><h3 id="_3단계-rule-count-≥-5" tabindex="-1">3단계: Rule (count ≥ 5) <a class="header-anchor" href="#_3단계-rule-count-≥-5" aria-label="Permalink to &quot;3단계: Rule (count ≥ 5)&quot;">​</a></h3><p>CQ가 <code>.claude/rules/</code>의 영구 규칙으로 승격합니다:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># 자동 생성 규칙 (hint에서 승격됨, count=5)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 실험 메트릭</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">항상 MPJPE, HD, MSD 순서로 평가하세요.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">결론을 내리기 전에 세 가지 모두를 보고하세요.</span></span></code></pre></div><p>규칙은 매 세션 시작 시 시스템 프롬프트에 로드됩니다. <code>CLAUDE.md</code>의 어떤 내용과도 동등하게 구속력이 있습니다.</p><h3 id="억제" tabindex="-1">억제 <a class="header-anchor" href="#억제" aria-label="Permalink to &quot;억제&quot;">​</a></h3><p>규칙을 삭제하면 CQ가 영구적으로 억제합니다 — 해당 선호도 패턴에서 다시는 승격되지 않습니다:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;mpjpe 먼저 확인&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 영구 억제</span></span></code></pre></div><h2 id="preferenceledger" tabindex="-1">PreferenceLedger <a class="header-anchor" href="#preferenceledger" aria-label="Permalink to &quot;PreferenceLedger&quot;">​</a></h2><p>Ledger가 선호도 이력을 저장합니다:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # 카운트와 함께 모든 선호도</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hints</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Hint만 (count ≥ 3)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rules</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Rule만 (count ≥ 5)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 특정 선호도 상세</span></span></code></pre></div><p>출력 예시:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ID       Count  Level  Preference</span></span>
<span class="line"><span>pref-01  5      RULE   Hub를 통해 자동으로 실험 실행</span></span>
<span class="line"><span>pref-02  4      HINT   @key=value 메트릭 출력 형식 사용</span></span>
<span class="line"><span>pref-03  4      HINT   MPJPE/HD/MSD 메트릭 먼저 확인</span></span>
<span class="line"><span>pref-04  2      -      커밋 전 임포트 정렬</span></span></code></pre></div><h2 id="지식이-외부로-흐릅니다" tabindex="-1">지식이 외부로 흐릅니다 <a class="header-anchor" href="#지식이-외부로-흐릅니다" aria-label="Permalink to &quot;지식이 외부로 흐릅니다&quot;">​</a></h2><p>선호도는 로컬에만 머물지 않습니다. <strong>GlobalPromoter</strong>가 식별 정보(경로, 사용자명, 이메일, 프로젝트명)를 제거하고 커뮤니티 지식 풀에 패턴을 기여합니다.</p><p>공유되는 것:</p><ul><li>행동 패턴 (&quot;메트릭 X를 Y보다 먼저 확인&quot;)</li><li>워크플로우 순서 (&quot;W 다음에 Z 실행&quot;)</li><li>도구 선호도 (&quot;U 대신 T 사용&quot;)</li></ul><p>절대 공유되지 않는 것:</p><ul><li>파일 경로</li><li>저장소 이름</li><li>이메일 주소</li><li>개인 식별자</li></ul><p>커뮤니티 패턴은 모든 사용자가 사용할 수 있습니다. 많은 사용자가 독립적으로 같은 모범 사례를 발견하면, 커뮤니티 풀에 노출되어 당신의 시행착오 단계를 건너뛸 수 있게 됩니다.</p><h2 id="세션과의-연동" tabindex="-1">세션과의 연동 <a class="header-anchor" href="#세션과의-연동" aria-label="Permalink to &quot;세션과의 연동&quot;">​</a></h2><p>Knowledge Loop는 세션 종료 시 자동으로 트리거됩니다:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> close</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 요약 + 선호도 추출 트리거</span></span></code></pre></div><p>또는 매 <code>cq claude</code> 종료 시 실행되도록 설정할 수 있습니다. 세션에서 추출된 선호도는 Ledger에 병합되고 카운트 증가가 원자적으로 발생합니다.</p><h2 id="pro와-team-티어" tabindex="-1">Pro와 Team 티어 <a class="header-anchor" href="#pro와-team-티어" aria-label="Permalink to &quot;Pro와 Team 티어&quot;">​</a></h2><p><strong>Pro</strong>와 <strong>Team</strong> 티어에서는 PreferenceLedger가 Supabase에 있어 다음에서 공유됩니다:</p><ul><li>모든 디바이스</li><li>모든 AI 도구 (Claude Code, ChatGPT, Cursor, Gemini)</li></ul><p>Claude Code 세션에서 관찰된 선호도가 다음 날 ChatGPT 세션에서 사용 가능합니다. Knowledge Loop는 하나의 도구가 아닌 전체 AI 사용에 걸쳐 쌓입니다.</p><p><strong>Free</strong> 티어에서는 Ledger가 로컬 SQLite에 있습니다. 선호도가 쌓이지만 디바이스나 도구 간에 동기화되지는 않습니다.</p><h2 id="비활성화" tabindex="-1">비활성화 <a class="header-anchor" href="#비활성화" aria-label="Permalink to &quot;비활성화&quot;">​</a></h2><p>세션 종료 시 자동 추출을 비활성화하려면:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># .c4/config.yaml</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">growth_loop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>전체 시스템을 비활성화하지 않고도 개별 규칙을 삭제하고 억제할 수 있습니다.</p>`,52)])])}const u=a(n,[["render",l]]);export{k as __pageData,u as default};
